initializeCommand:
set -euo pipefail && \
  # Verify that the workspace directory exists (Docker will create it when mounting the named volume)
  if [ ! -d /home/vscode/data-infra ]; then
    echo '❌ /home/vscode/data-infra does not exist – the named volume probably failed to mount.' >&2;
    exit 1;
  fi && \
  # Populate the volume only if it is empty
  if [ -z "$(ls -A /home/vscode/data-infra 2>/dev/null)" ]; then
    echo '🔧 Populating named volume with repository …';
    sudo cp -a "${localWorkspaceFolder}/." /home/vscode/data-infra/ &&
    sudo chown -R $(id -u vscode):$(id -g vscode) /home/vscode/data-infra &&
    echo '✅ Repository copied and ownership set.';
  else
    echo '✅ Volume already contains the repository – nothing to copy.';
  fi
